<span class="line"><span style="color:#CDD6F4;">        branches</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">branch_name</span><span style="color:#9399B2;">);</span></span>
