<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">trim_start_matches</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;agent/&quot;</span><span style="color:#9399B2;">)</span></span>
